if (! function_exists('text_autocomplete')) {
    function text_autocomplete($prefix, $wordlist, $mode = null, $max_results = null, $case_sensitive = null)
    {
        $prefix = trim($prefix);
        if (empty($prefix) || !is_array($wordlist) || empty($wordlist)) {
            return json_encode(['error' => 'Prefix and non-empty wordlist are required', 'suggestions' => []]);
        }
        $mode = isset($mode) ? $mode : 'prefix';
        $max = isset($max_results) && $max_results > 0 ? (int)$max_results : 10;
        $caseSensitive = isset($case_sensitive) ? (bool)$case_sensitive : false;

        $prefixLen = strlen($prefix);
        $scores = [];

        foreach ($wordlist as $candidate) {
            $cand = trim((string)$candidate);
            if ($cand === '' || $cand === $prefix) continue;

            $candCompare = $caseSensitive ? $cand : mb_strtolower($cand);
            $prefixCompare = $caseSensitive ? $prefix : mb_strtolower($prefix);

            if ($mode === 'prefix') {
                // Exact prefix match
                if (strpos($candCompare, $prefixCompare) === 0) {
                    // Score: shorter words closer to prefix length rank higher
                    $score = 100 - abs(strlen($cand) - $prefixLen);
                    $scores[] = ['word' => $cand, 'score' => $score, 'match_type' => 'prefix'];
                }
            } elseif ($mode === 'fuzzy') {
                // Fuzzy prefix: Levenshtein distance on the prefix portion
                $candStart = substr($candCompare, 0, $prefixLen);
                $dist = levenshtein($prefixCompare, $candStart);

                // Also check if the prefix appears anywhere in the word
                $containsPos = strpos($candCompare, $prefixCompare);

                if ($dist <= 2 || $containsPos !== false) {
                    $score = 50;
                    if ($dist === 0) $score = 100; // exact prefix
                    elseif ($dist === 1) $score = 70; // off by 1 char
                    elseif ($dist === 2) $score = 40; // off by 2 chars
                    if ($containsPos !== false) $score += 10; // bonus for substring match
                    $score -= abs(strlen($cand) - $prefixLen); // penalty for length diff
                    $matchType = $dist === 0 ? 'prefix' : ($containsPos !== false ? 'contains' : 'fuzzy');
                    $scores[] = ['word' => $cand, 'score' => $score, 'match_type' => $matchType];
                }
            }
        }

        // Sort by score descending
        usort($scores, function($a, $b) { return $b['score'] - $a['score']; });

        $results = array_slice($scores, 0, $max);

        return json_encode([
            'prefix' => $prefix,
            'mode' => $mode,
            'candidates_checked' => count($wordlist),
            'matches_found' => count($scores),
            'suggestions' => $results,
        ]);
    }
